arguments.command:
cd ~/projects/ReviewLens
echo "=== Existing ai-transcripts/ ===" && ls -la ai-transcripts/ 2>/dev/null || echo "(does not exist)"
echo "" && echo "=== Git repo? ===" && git rev-parse --is-inside-work-tree 2>/dev/null && echo "" && echo "=== .gitignore mentions ai-transcripts? ===" && (grep -n "ai-transcripts" .gitignore 2>/dev/null || echo "not in .gitignore")
echo "" && echo "=== Largest codex files (top 5) ===" && python3 -c "import json,glob,os; fs=[f for r in ['sessions','archived_sessions'] for f in glob.glob(os.path.expanduser('~/.codex/'+r)+'/**/*.jsonl',recursive=True)]; 
import sys
out=[]
for f in fs:
  with open(f,errors='replace') as fh:
    for line in fh:
      line=line.strip()
      if not line: continue
      o=json.loads(line)
      if o.get('type')=='session_meta' and 'ReviewLens' in o.get('payload',{}).get('cwd',''):
        out.append((os.path.getsize(f),f)); break
out.sort(reverse=True)
for s,f in out[:5]: print(f'{s/1024/1024:.1f} MB  {os.path.basename(f)}')"

cd ~/projects/ReviewLens
python3 <<'EOF'
import json, os, glob, shutil

DST = "ai-transcripts"
copied = []

def cp(src, dst_rel):
    dst = os.path.join(DST, dst_rel)
    os.makedirs(os.path.dirname(dst) or ".", exist_ok=True)
    shutil.copy2(src, dst)
    copied.append(dst)

# ---------- CLAUDE ----------
claude_map = {
    "~/.claude/projects/-Users-dpaluy-projects-ReviewLens":    "claude/projects-ReviewLens",
    "~/.claude/projects/-Users-dpaluy-projects-ReviewLens-ui": "claude/projects-ReviewLens-ui",
}
for src_root, dst_root in claude_map.items():
    src_root = os.path.expanduser(src_root)
    for root, _, fns in os.walk(src_root):
        for fn in fns:
            rel = os.path.relpath(os.path.join(root, fn), src_root)
            cp(os.path.join(root, fn), os.path.join(dst_root, rel))

# ---------- CODEX (cwd-validated) ----------
codex_roots = [os.path.expanduser("~/.codex/sessions"), os.path.expanduser("~/.codex/archived_sessions")]
for root in codex_roots:
    for f in glob.glob(os.path.join(root, "**", "*.jsonl"), recursive=True):
        with open(f, errors="replace") as fh:
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                obj = json.loads(line)
                if obj.get("type") == "session_meta":
                    cwd = obj.get("payload", {}).get("cwd", "")
                    if "ReviewLens" in cwd:
                        # keep active vs archived provenance
                        sub = "sessions" if "/sessions/" in f else "archived_sessions"
                        cp(f, f"codex/{sub}/{os.path.basename(f)}")
                    break

# ---------- PI ----------
pi_map = {
    "--Users-dpaluy-projects-ReviewLens--":              "pi/projects-ReviewLens",
    "--Users-dpaluy-.codex-worktrees-80b8-ReviewLens--": "pi/worktrees-80b8-ReviewLens",
    "--Users-dpaluy-projects-ReviewLens.chore-ui-chat--":"pi/projects-ReviewLens-chore-ui-chat",
}
pidir = os.path.expanduser("~/.pi/agent/sessions")
for sub, dst_root in pi_map.items():
    src_root = os.path.join(pidir, sub)
    for root, _, fns in os.walk(src_root):
        for fn in fns:
            rel = os.path.relpath(os.path.join(root, fn), src_root)
            cp(os.path.join(root, fn), os.path.join(dst_root, rel))

print(f"Copied {len(copied)} files into {DST}/")
EOF
